  Selectable<DictionarySearchFts5DriftResult> dictionary_search_fts5_drift(
    String query,
    int? spellfixDistance,
    int useGlob,
    String ftsQuery,
    String posFilter,
  ) {
    return customSelect(
      'WITH SpellfixSuggestions AS (SELECT word, distance FROM reading_spellfix WHERE word MATCH ?1 AND distance > 0 AND distance < ?2 AND ?3 = 0 ORDER BY distance LIMIT 10), FtsMatches AS (SELECT TB3T.id AS term_bank_id, rank, TT.term AS matched_text, highlight(term_fts, 0, \'\', \'\') AS highlighted_text, CASE WHEN TT.term = ?1 THEN 1 WHEN TT.term LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 1 AS match_column_priority, NULL AS spellfix_suggestion FROM term_fts AS FTS JOIN term_bank_v3_table AS TB3T ON FTS."rowid" = TB3T.term_id JOIN term_table AS TT ON FTS."rowid" = TT.id WHERE ?3 = 0 AND term_fts MATCH ?4 UNION ALL SELECT TB3T.id AS term_bank_id, rank, RT.reading AS matched_text, highlight(reading_fts, 0, \'\', \'\') AS highlighted_text, CASE WHEN RT.reading = ?1 THEN 1 WHEN RT.reading LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 2 AS match_column_priority, NULL AS spellfix_suggestion FROM reading_fts AS FTS JOIN term_bank_v3_table AS TB3T ON FTS."rowid" = TB3T.reading_id JOIN reading_table AS RT ON FTS."rowid" = RT.id WHERE ?3 = 0 AND reading_fts MATCH ?4 UNION ALL SELECT DefJoin.term_bank_id, rank, DT.definition AS matched_text, highlight(definition_fts, 0, \'\', \'\') AS highlighted_text, CASE WHEN DT.definition = ?1 THEN 1 WHEN DT.definition LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 3 AS match_column_priority, NULL AS spellfix_suggestion FROM definition_fts AS FTS JOIN term_bank_v3_x_definition_table AS DefJoin ON FTS."rowid" = DefJoin.definition_id JOIN definition_table AS DT ON FTS."rowid" = DT.id WHERE ?3 = 0 AND definition_fts MATCH ?4), GlobMatches AS (SELECT TB3T.id AS term_bank_id, 0 AS rank, TT.term AS matched_text, TT.term AS highlighted_text, CASE WHEN TT.term = ?1 THEN 1 WHEN TT.term LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 1 AS match_column_priority, NULL AS spellfix_suggestion FROM term_table AS TT JOIN term_bank_v3_table AS TB3T ON TT.id = TB3T.term_id WHERE ?3 = 1 AND TT.term GLOB ?1 UNION ALL SELECT TB3T.id AS term_bank_id, 0 AS rank, RT.reading AS matched_text, RT.reading AS highlighted_text, CASE WHEN RT.reading = ?1 THEN 1 WHEN RT.reading LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 2 AS match_column_priority, NULL AS spellfix_suggestion FROM reading_table AS RT JOIN term_bank_v3_table AS TB3T ON RT.id = TB3T.reading_id WHERE ?3 = 1 AND RT.reading GLOB ?1 UNION ALL SELECT DefJoin.term_bank_id, 0 AS rank, DT.definition AS matched_text, DT.definition AS highlighted_text, CASE WHEN DT.definition = ?1 THEN 1 WHEN DT.definition LIKE ?1 || \'%\' THEN 2 ELSE 3 END AS match_type_priority, 3 AS match_column_priority, NULL AS spellfix_suggestion FROM definition_table AS DT JOIN term_bank_v3_x_definition_table AS DefJoin ON DT.id = DefJoin.definition_id WHERE ?3 = 1 AND DT.definition GLOB ?1), RankedIDs AS (SELECT * FROM FtsMatches UNION ALL SELECT * FROM GlobMatches UNION ALL SELECT TB3T.id AS term_bank_id, S.distance AS rank, RT.reading AS matched_text, RT.reading AS highlighted_text, 4 AS match_type_priority, 2 AS match_column_priority, S.word AS spellfix_suggestion FROM SpellfixSuggestions AS S JOIN reading_table AS RT ON S.word = RT.reading JOIN term_bank_v3_table AS TB3T ON RT.id = TB3T.reading_id), FilteredByPoS AS (SELECT T3XDT.term_bank_id FROM term_bank_v3_x_definition_tag_table AS T3XDT JOIN term_bank_v3_definition_tags_table AS T3DT ON T3DT.id = T3XDT.definition_tag_id WHERE LENGTH(?5) > 2 AND T3DT.definition_tag IN (SELECT value FROM json_each(?5)) GROUP BY T3XDT.term_bank_id), FinalRankedIDs AS (SELECT term_bank_id, rank AS best_rank, match_type_priority, match_column_priority, highlighted_text, matched_text, spellfix_suggestion FROM (SELECT *, ROW_NUMBER()OVER (PARTITION BY term_bank_id ORDER BY match_type_priority, match_column_priority, rank RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW EXCLUDE NO OTHERS) AS rn FROM RankedIDs WHERE(LENGTH(?5) <= 2)OR(term_bank_id IN (SELECT term_bank_id FROM FilteredByPoS))) WHERE rn = 1) SELECT R.best_rank AS fts5_rank, matched_text, highlighted_text, R.match_type_priority, R.match_column_priority, R.spellfix_suggestion, V.* FROM term_bank_v3_search_view AS V JOIN FinalRankedIDs AS R ON V.id = R.term_bank_id ORDER BY R.match_type_priority, R.match_column_priority, V.popularity DESC, R.best_rank',
      variables: [
        Variable<String>(query),
        Variable<int>(spellfixDistance),
        Variable<int>(useGlob),
        Variable<String>(ftsQuery),
        Variable<String>(posFilter),
      ],
      readsFrom: {
        readingSpellfix,
        termBankV3Table,
        termFts,
        termTable,
        readingFts,
        readingTable,
        termBankV3XDefinitionTable,
        definitionFts,
        definitionTable,
        termBankV3XDefinitionTagTable,
        termBankV3DefinitionTagsTable,
        termBankV3XRuleIdentifierTable,
        termBankV3RuleIdentifierTable,
        termBankV3XTagBankTable,
        tagBankV3Table,
      },
    ).map(
      (QueryRow row) => DictionarySearchFts5DriftResult(
        fts5Rank: row.readNullable<double>('fts5_rank'),
        matchedText: row.read<String>('matched_text'),
        highlightedText: row.readNullable<String>('highlighted_text'),
        matchTypePriority: row.read<int>('match_type_priority'),
        matchColumnPriority: row.read<int>('match_column_priority'),
        spellfixSuggestion: row.readNullable<String>('spellfix_suggestion'),
        id: row.read<int>('id'),
        term: row.readNullable<String>('term'),
        reading: row.readNullable<String>('reading'),
        definitionTags: row.read<String>('definition_tags'),
        ruleIdentifiers: row.read<String>('rule_identifiers'),
        popularity: row.read<int>('popularity'),
        definitions: row.read<String>('definitions'),
        definitionOrder: $TermBankV3TableTable.$converterdefinitionOrder
            .fromSql(row.read<String>('definition_order')),
        sequenceNumber: row.read<int>('sequence_number'),
        tags: row.read<String>('tags'),
      ),
    );
  }

  Selectable<GetMbSizesDriftResult> get_mb_sizes_drift() {
    return customSelect(
      'SELECT name, sum(pgsize) AS bytes, format(\'%.2f MB\', CAST(sum(pgsize) AS REAL) /(1024 * 1024)) AS megabytes FROM dbstat GROUP BY name ORDER BY bytes DESC',
      variables: [],
      readsFrom: {},
    ).map(
      (QueryRow row) => GetMbSizesDriftResult(
        name: row.read<String>('name'),
        bytes: row.readNullable<int>('bytes'),
        megabytes: row.read<String>('megabytes'),
      ),
    );
  }

